function commonsDescriptionUrl(fileName: string) {
  return `https://commons.wikimedia.org/wiki/File:${encodeURIComponent(fileName.replace(/ /g, "_"))}`;
}

export const PAINTINGS: readonly PaintingRecord[] = PAINTING_ROWS.map(
  ([qid, articleTitle, title, artist, year, fallbackFile, width, height]) => {
    const descriptionUrl = commonsDescriptionUrl(fallbackFile);
    return {
      qid,
      articleTitle,
      title,
      artist,
      year,
      fallbackFile,
      width,
      height,
      license: "Public domain",
      licenseUrl: descriptionUrl,
      descriptionUrl,
    };
  },
);
